import pytest

from your_module import fizzbuzz  # change to the actual module name


@pytest.mark.parametrize(
    "n, expected",
    [
        (1, "1"),      # happy path: neither 3 nor 5
        (2, "2"),
        (3, "Fizz"),   # divisible by 3
        (5, "Buzz"),   # divisible by 5
        (6, "Fizz"),   # divisible by 3 only
        (10, "Buzz"),  # divisible by 5 only
        (15, "FizzBuzz"),  # divisible by both 3 and 5
        (30, "FizzBuzz"),
    ],
)
def test_fizzbuzz_returns_expected_output(n, expected):
    assert fizzbuzz(n) == expected


@pytest.mark.parametrize(
    "n",
    [
        0,    # edge case: 0 is divisible by 15
        -3,   # negative divisible by 3
        -5,   # negative divisible by 5
        -15,  # negative divisible by 15
    ],
)
def test_fizzbuzz_handles_zero_and_negative_numbers(n):
    result = fizzbuzz(n)
    if n % 15 == 0:
        assert result == "FizzBuzz"
    elif n % 3 == 0:
        assert result == "Fizz"
    elif n % 5 == 0:
        assert result == "Buzz"
    else:
        assert result == str(n)


@pytest.mark.parametrize(
    "n",
    [
        1.5,
        "3",
        None,
        [],
        {},
    ],
)
def test_fizzbuzz_raises_type_error_for_invalid_inputs(n):
    with pytest.raises(TypeError):
        fizzbuzz(n)
